// Paramètres : passés en query string ou valeurs par défaut
// Exemple d'appel : GET /webhook/test-vitesse-voix?voice_id=tMyQcCxfGDdIt7wJ2RQw
const voice_id = $input.item.json.query?.voice_id || 'tMyQcCxfGDdIt7wJ2RQw';
const script = $input.item.json.query?.script || 'Il y a une femme qui m a envoye un message. Elle est assistante administrative. CDI. 37 ans. Deux garcons. Elle m a dit que son fils lui avait dit : maman, elle rentre toujours tard. Elle avait reduit son contrat a 60 pourcent pour etre plus la. Et ca suffisait pas.';
return [{ json: { voice_id, script } }];

const results = $input.item.json.results || [];
const note = $input.item.json.note || '';

const cardsHtml = results.map(r => {
  const speedLabel = r.speed === 1.0 ? '1.0x (normale)'
    : r.speed === 1.2 ? '1.2x (rapide)'
    : r.speed === 1.5 ? '1.5x (très rapide)'
    : '2.0x (maximum)';
  const extra = r.creatomate_multiplier > 1
    ? `<span style="font-size:11px;color:#888">ElevenLabs 1.2x + Creatomate x${r.creatomate_multiplier}</span>`
    : `<span style="font-size:11px;color:#888">ElevenLabs natif</span>`;
  return `<div style="margin:16px 0;padding:16px;border:1px solid #ddd;border-radius:10px;background:#fafafa">
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px">
      <strong style="font-size:16px">${speedLabel}</strong>
      <span style="background:#e8f4fd;color:#1a73e8;padding:3px 10px;border-radius:12px;font-size:13px">${r.duration_seconds.toFixed(1)}s</span>
    </div>
    ${extra}
    <audio controls style="width:100%;margin-top:8px" src="${r.audio_url}"></audio>
    <p style="margin:8px 0 0;font-size:12px;color:#555">👉 Pour utiliser cette vitesse : colonne <strong>Vitesse voix</strong> = <code>${r.speed}</code></p>
  </div>`;
}).join('');

const html = `<!DOCTYPE html>
<html lang="fr">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>Test Vitesse Voix — VideoGen</title>
  <style>
    body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; max-width: 580px; margin: 0 auto; padding: 24px 16px; color: #222; }
    h1 { font-size: 22px; margin-bottom: 4px; }
    .subtitle { color: #666; margin-bottom: 24px; font-size: 14px; }
    .note { background: #fff8e1; border-left: 4px solid #ffc107; padding: 12px 16px; border-radius: 4px; font-size: 13px; margin-top: 24px; }
  </style>
</head>
<body>
  <h1>🎙️ Test Vitesse Voix</h1>
  <p class="subtitle">Écoute les 4 versions — choisit ta préférée — note la valeur dans la colonne <strong>Vitesse voix</strong> du Sheet.</p>
  ${cardsHtml}
  <div class="note">${note}</div>
</body>
</html>`;

return [{ json: { html } }];
